class Queue:
  def __init__(self, n):
    self.size = 0
    self.arr = [0] * n
    self.front = 0

  def enqueue(self, val):
    if self.size < len(self.arr):
      self.arr[self.size] = val
      self.size += 1

  def dequeue(self):
    if self.size > 0:
      val = self.arr[self.front]
      self.arr[self.front] = 0
      self.front += 1
      self.size -= 1
      return val
    return -1

class Solution:
  def dequeue(self, q, arr):
    return q.dequeue()

