class Solution {
public:
  int dequeue(Queue& q, std::vector<int>& arr) {
    return q.dequeue();
  }
};

int main() {
  int n;
  std::cin >> n;
  Queue q(n);
  for (int i = 0; i < n; ++i) {
    int temp;
    std::cin >> temp;
    q.enqueue(temp);
  }
  int result = Solution().dequeue(q, std::vector<int>());
  std::cout << result << std::endl;
  return 0;
}
